import React, { useState, useEffect } from "react";
import { ReactComponent as BoliviaSVG } from "../assets/bolivia.svg";

const MapaBolivia = ({ onDepartamentoClick, empresas }) => {
    const [departamentoSeleccionado, setDepartamentoSeleccionado] = useState(null);

    const manejarClick = (e) => {
        const nombre = e.target.getAttribute("name");
        if (nombre) {
            setDepartamentoSeleccionado(nombre);
            if (onDepartamentoClick) {
                onDepartamentoClick(nombre);
            }
        }
    };

    useEffect(() => {
        // Código para cambiar el color de los departamentos
        const paths = document.querySelectorAll(".bolivia-map path");
        paths.forEach((path) => {
            const nombreDep = path.getAttribute("name");
            if (nombreDep === departamentoSeleccionado) {
                path.style.fill = "#000000ff"; // Color para el departamento seleccionado
            } else {
                path.style.fill = "#32302fff"; // Color por defecto
            }
        });
    }, [departamentoSeleccionado]);

    return (
        // 1. Contenedor principal: Usamos 'max-w-full' para evitar desbordamiento horizontal.
        //    Quitamos 'h-full' del contenedor más externo para dejar que el contenido defina la altura.
        <div className="w-full flex items-center justify-center">
            {/* 2. Contenedor del SVG: Aplicamos un 'aspect-square' o 'aspect-video'
                 si estás usando Tailwind 3+. Si no, usamos 'relative' y 'pt-[x%]' para el aspecto.
                 Usaremos un padding superior para forzar la proporción (ej. 100% para un cuadrado o 75% para 4:3)
                 Si tu mapa es más ancho que alto, usa un valor menor (ej. pt-[70%]).
            */}
            <div className="flex-grow w-full relative" style={{ paddingTop: '100%' }}> 
                <BoliviaSVG
                    // 3. SVG: Posicionamos de forma absoluta para ocupar el espacio del padding.
                    //    Añadimos 'object-contain' para asegurar que el SVG se ajuste sin cortarse.
                    className="bolivia-map w-full h-full cursor-pointer absolute top-0 left-0 object-contain"
                    onClick={manejarClick}
                />
            </div>
        </div>
    );
};

export default MapaBolivia;
